mapper.select:
select T1.*,T2.job_number as jobNumber FROM ( select emp_id as employeeId, sum(CASE WHEN field_name='早退时长' THEN value ELSE 0 END) earlyMinute, sum(CASE WHEN field_name='早退次数' THEN value ELSE 0 END) earlyCount, sum(CASE WHEN field_name in ('迟到时长') THEN value ELSE 0 END) lateMinute, sum(CASE WHEN field_name in ('迟到次数') THEN value ELSE 0 END) lateCount, sum(CASE WHEN field_name in ('旷工天数','旷工迟到天数') THEN value ELSE 0 END) absenteeismDays, sum(CASE WHEN field_name in ('上班缺卡次数','下班缺卡次数') THEN value ELSE 0 END) misscardCount, sum(CASE WHEN field_name in ('工作日加班') THEN value ELSE 0 END) workDateOverTime, sum(CASE WHEN field_name in ('休息日加班') THEN value ELSE 0 END) restOverTime, sum(CASE WHEN field_name in ('节假日加班') THEN value ELSE 0 END) holidayOverTime, sum(CASE WHEN field_name in ('加班-审批单统计') THEN value ELSE 0 END) overTimeHours, sum(CASE WHEN field_name='出勤天数' THEN value ELSE 0 END) actualityDays, sum(CASE WHEN field_name='产假' THEN value ELSE 0 END) chanjia, sum(CASE WHEN field_name='婚假' THEN value ELSE 0 END) hunjia, sum(CASE WHEN field_name='陪产假' THEN value ELSE 0 END) peichanjia, sum(CASE WHEN field_name='丧假' THEN value ELSE 0 END) sangjia, sum(CASE WHEN field_name='事假' THEN value ELSE 0 END) shijia, sum(CASE WHEN field_name='病假' THEN value ELSE 0 END) bingjia, sum(CASE WHEN field_name='调休' THEN value ELSE 0 END) tiaoxiu, sum(CASE WHEN field_name='年假' THEN value ELSE 0 END) nianjia, sum(CASE WHEN field_name='哺乳假' THEN value ELSE 0 END) burujia from hrm_attendance_report_data WHERE work_date BETWEEN #{beginDate} and #{endDate}
and emp_id=#{employeeId}
GROUP BY emp_id ) T1 left join hrm_employee T2 on T1.employeeId = T2.employee_id

select T1.* from ( SELECT emp_id as employeeId,work_date as workDate, sum(CASE WHEN field_name='早退时长' THEN value ELSE 0 END) earlyMinute, sum(CASE WHEN field_name='早退次数' THEN value ELSE 0 END) earlyCount, sum(CASE WHEN field_name in ('迟到时长') THEN value ELSE 0 END) lateMinute, sum(CASE WHEN field_name in ('迟到次数') THEN value ELSE 0 END) lateCount, sum(CASE WHEN field_name in ('出勤天数') THEN value ELSE 0 END) actualityDays, sum(CASE WHEN field_name='病假' THEN value ELSE 0 END) bingjia, sum(CASE WHEN field_name='事假' THEN value ELSE 0 END) shijia FROM hrm_attendance_report_data t1 WHERE work_date BETWEEN #{beginDate} and #{endDate}
and emp_id=#{employeeId}
GROUP BY emp_id,work_date ) T1
